1	import type { ResultStatus, RunStatus } from '../../api/runs';
2	
3	/**
4	 * Pure presentation helpers for the Results surface — kept framework-free so the
5	 * status→colour mapping and the timing formatters can be unit-tested without
6	 * rendering antd.
7	 */
8	
9	/** antd Tag colour per run execution status. */
10	export const RUN_STATUS_COLORS: Record<RunStatus, string> = {
11	  queued: 'default',
12	  running: 'processing',
13	  succeeded: 'success',
14	  failed: 'error',
15	  cancelled: 'warning',
16	};
17	
18	/** antd Tag colour per result severity / operational status (ADR 0005 / #122). */
19	export const RESULT_STATUS_COLORS: Record<ResultStatus, string> = {
20	  pass: 'success',
21	  warn: 'warning',
22	  fail: 'error',
23	  critical: 'magenta',
24	  skip: 'default',
25	  error: 'volcano',
26	};
27	
28	/** Orchestrator pipeline-run status → colour (provider-agnostic value set). */
29	export function pipelineStatusColor(status: string): string {
