import { App, Button, Drawer, Flex, Form, Input, Select, Typography } from 'antd';
import { useEffect, useState } from 'react';

import { type Check, updateCheck } from '../../api/suites';
import { buildCheckPayload, configToForm } from './checkForm';
import { ConfigFieldItem, SeverityThresholdFields } from './checkFormFields';
import { ColumnProfilePanel } from './ColumnProfilePanel';
import { DryRunPreview } from './DryRunPreview';
import { EXPECTATION_BY_TYPE, EXPECTATIONS_BY_CATEGORY } from './expectationCatalog';

/**
 * Edit a GX check. The expectation Select (grouped by category) drives which
 * config fields render (from the expectation catalog); the submitted `config` is
 * rebuilt from only the selected expectation's declared fields, so switching
 * types never leaks stale kwargs. Creating a check is the dedicated
 * `/suites/:suiteId/checks/new` page, not this drawer.
 */
export function CheckDrawer({
  open,
  suiteId,
  check,
  target,
  onClose,
  onSaved,
}: {
  open: boolean;
  suiteId: string;
  check?: Check;
  /** The suite's run target (#215) — drives the dry-run preview's table/schema. */
  target: Record<string, unknown> | null;
  onClose: () => void;
  onSaved: () => void;
}) {
  const { message } = App.useApp();
  const [form] = Form.useForm();
  const [submitting, setSubmitting] = useState(false);
  const selectedType = Form.useWatch('expectation_type', form) as string | undefined;
  const column = Form.useWatch(['config', 'column'], form) as string | undefined;
  const spec = selectedType ? EXPECTATION_BY_TYPE[selectedType] : undefined;

  // Reset first (antd keeps values for unmounted fields, so stale config can
  // survive an open→close→open with a different check), then prefill.
  useEffect(() => {
    if (!open || !check) return;
    form.resetFields();
    form.setFieldsValue({
      name: check.name,
      expectation_type: check.expectation_type,
      config: configToForm(EXPECTATION_BY_TYPE[check.expectation_type], check.config),
      warn_threshold: check.warn_threshold ?? undefined,
      fail_threshold: check.fail_threshold ?? undefined,
      critical_threshold: check.critical_threshold ?? undefined,
    });
  }, [open, check, form]);

  const onSubmit = async () => {
    if (!check) return;
    let values: Record<string, unknown>;
    try {
      values = await form.validateFields();
    } catch {
      return; // inline validation errors
    }
    const payload = buildCheckPayload(values);
    setSubmitting(true);
    try {
      await updateCheck(suiteId, check.id, payload);
      message.success(`${payload.name}: saved`);
      onSaved();
    } catch (err) {
      message.error(`Save failed: ${err instanceof Error ? err.message : 'unknown error'}`);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Drawer
      title={check ? `Edit “${check.name}”` : 'Edit check'}
      open={open}
      onClose={onClose}
      width={520}
      destroyOnHidden
      extra={
        <Flex gap={8}>
          <Button onClick={onClose}>Cancel</Button>
          <Button type="primary" loading={submitting} onClick={onSubmit}>
            Save
          </Button>
        </Flex>
      }
    >
      <Form form={form} layout="vertical">
        <Form.Item name="name" label="Name" rules={[{ required: true }]}>
          <Input placeholder="e.g. order_id not null" />
        </Form.Item>
        <Form.Item name="expectation_type" label="Expectation" rules={[{ required: true }]}>
          <Select
            placeholder="Select an expectation"
            // Grouped by category (antd optgroups) — the GX-Cloud-style picker.
            options={EXPECTATIONS_BY_CATEGORY.map((g) => ({
              label: g.category,
              options: g.specs.map((e) => ({ value: e.type, label: e.label })),
            }))}
          />
        </Form.Item>

        {spec && (
          <>
            <Typography.Paragraph type="secondary" style={{ marginTop: -8 }}>
              {spec.description}
            </Typography.Paragraph>
            {spec.fields.map((field) => (
              <ConfigFieldItem key={field.name} field={field} />
            ))}
          </>
        )}

        <SeverityThresholdFields />

        <ColumnProfilePanel suiteId={suiteId} target={target} column={column} />

        <DryRunPreview
          suiteId={suiteId}
          expectationType={selectedType}
          target={target}
          form={form}
        />
      </Form>
    </Drawer>
  );
}

import { api } from './client';

/**
 * Suites API — a suite is a named bundle of DQ checks bound to one connection.
 * `connection_id` is set at create and immutable thereafter (re-pointing would
 * orphan the child checks), mirroring the backend `suite_service` contract.
 */

/** Mirrors the backend `SuiteRead` schema. */
export interface Suite {
  id: string;
  name: string;
  description: string | null;
  connection_id: string;
  /** Datasource-shaped run target (#215); null = not yet runnable. */
  target: Record<string, unknown> | null;
  created_by: string;
}

/** Mirrors `SuiteCreate` — connection_id is required and immutable. */
export interface SuiteCreate {
  name: string;
  description?: string | null;
  connection_id: string;
}

/** Mirrors `SuiteUpdate` — only name/description are mutable. */
export interface SuiteUpdate {
  name?: string;
  description?: string | null;
}

export async function listSuites(params?: { connection_id?: string }): Promise<Suite[]> {
  const { data } = await api.get<Suite[]>('/suites', { params });
  return data;
}

export async function getSuite(id: string): Promise<Suite> {
  const { data } = await api.get<Suite>(`/suites/${id}`);
  return data;
}

export async function createSuite(payload: SuiteCreate): Promise<Suite> {
  const { data } = await api.post<Suite>('/suites', payload);
  return data;
}

export async function updateSuite(id: string, payload: SuiteUpdate): Promise<Suite> {
  const { data } = await api.patch<Suite>(`/suites/${id}`, payload);
  return data;
}

export async function deleteSuite(id: string): Promise<void> {
  await api.delete(`/suites/${id}`);
}

/** Mirrors the backend `CheckRead` schema (read-only here — editor is a later slice). */
export interface Check {
  id: string;
  suite_id: string;
  name: string;
  kind: string;
  expectation_type: string;
  config: Record<string, unknown>;
  warn_threshold: number | null;
  fail_threshold: number | null;
  critical_threshold: number | null;
}

export async function listChecks(suiteId: string): Promise<Check[]> {
  const { data } = await api.get<Check[]>(`/suites/${suiteId}/checks`);
  return data;
}

/** Mirrors `CheckCreate` — v1 only authors `kind: 'expectation'` (service-enforced). */
export interface CheckCreate {
  name: string;
  expectation_type: string;
  config: Record<string, unknown>;
  warn_threshold?: number | null;
  fail_threshold?: number | null;
  critical_threshold?: number | null;
}

/** Mirrors `CheckUpdate` — all fields optional; kind is immutable. */
export interface CheckUpdate {
  name?: string;
  expectation_type?: string;
  config?: Record<string, unknown>;
  warn_threshold?: number | null;
  fail_threshold?: number | null;
  critical_threshold?: number | null;
}

export async function createCheck(suiteId: string, payload: CheckCreate): Promise<Check> {
  const { data } = await api.post<Check>(`/suites/${suiteId}/checks`, payload);
  return data;
}

export async function updateCheck(
  suiteId: string,
  checkId: string,
  payload: CheckUpdate,
): Promise<Check> {
  const { data } = await api.patch<Check>(`/suites/${suiteId}/checks/${checkId}`, payload);
  return data;
}

export async function deleteCheck(suiteId: string, checkId: string): Promise<void> {
  await api.delete(`/suites/${suiteId}/checks/${checkId}`);
}

/** Mirrors `CheckDryRunRequest` — preview one check against live data, no persist.
 *  `table`/`schema` come from the suite's run target (#215). v1: Snowflake only. */
export interface CheckDryRunRequest {
  expectation_type: string;
  config: Record<string, unknown>;
  warn_threshold?: number | null;
  fail_threshold?: number | null;
  critical_threshold?: number | null;
  table: string;
  schema?: string | null;
}

/** Mirrors `CheckDryRunResult` — the preview outcome (severity tier + metric). */
export interface CheckDryRunResult {
  status: string; // pass | warn | fail | critical
  metric_value: number | null;
  observed_value: Record<string, unknown> | null;
  expected_value: Record<string, unknown> | null;
}

export async function dryRunCheck(
  suiteId: string,
  payload: CheckDryRunRequest,
): Promise<CheckDryRunResult> {
  const { data } = await api.post<CheckDryRunResult>(`/suites/${suiteId}/checks/dryrun`, payload);
  return data;
}

/** Mirrors the backend `ColumnProfileRequest` — profile columns of the suite's
 *  table/file (no persistence). The target identity (`table`/`schema`/`catalog`
 *  for SQL, `path`/`file_format` for flat files) comes from the suite's run
 *  target (#215); `columns` is the subset to profile. */
export interface ColumnProfileRequest {
  columns: string[];
  top_n?: number;
  table?: string | null;
  schema?: string | null;
  catalog?: string | null;
  path?: string | null;
  file_format?: 'csv' | 'parquet' | null;
}

/** Mirrors the backend `TopValue` — a value and how often it occurs. */
export interface TopValue {
  value: unknown;
  count: number;
}

/** Mirrors the backend `ColumnProfileRead` — per-column stats. */
export interface ColumnProfile {
  column: string;
  null_count: number;
  null_fraction: number;
  distinct_count: number | null;
  min_value: unknown;
  max_value: unknown;
  top_values: TopValue[];
}

/** Mirrors the backend `ProfileRead` — row count + per-column stats. Identity
 *  fields are type-specific (SQL fills `table`/`schema`/`catalog`, flat files
 *  fill `path`/`file_format`). */
export interface ProfileResult {
  row_count: number;
  columns: ColumnProfile[];
  table?: string | null;
  schema?: string | null;
  catalog?: string | null;
  path?: string | null;
  file_format?: string | null;
}

export async function profileColumns(
  suiteId: string,
  payload: ColumnProfileRequest,
): Promise<ProfileResult> {
  const { data } = await api.post<ProfileResult>(`/suites/${suiteId}/profile`, payload);
  return data;
}

